from dataclasses import dataclass


@dataclass(frozen=True)
class Lease:
    worker_id: str
    generation: int


class LeaseRegistry:
    def __init__(self):
        self._next_generation = {}
        self._active = {}

    def acquire(self, worker_id):
        generation = self._next_generation.get(worker_id, 0) + 1
        self._next_generation[worker_id] = generation
        lease = Lease(worker_id, generation)
        self._active[worker_id] = lease
        return lease

    def release(self, lease):
        return self._active.pop(lease.worker_id, None) is not None

    def is_active(self, lease):
        return self._active.get(lease.worker_id) == lease

    def current(self, worker_id):
        return self._active.get(worker_id)

