from dataclasses import dataclass


@dataclass
class Task:
    task_id: str
    payload: object
    state: str = "pending"
    owner_id: str | None = None
    owner_generation: int | None = None


class TaskQueue:
    def __init__(self):
        self._tasks = {}

    def add(self, task_id, payload):
        if task_id in self._tasks:
            raise ValueError("duplicate task")
        self._tasks[task_id] = Task(task_id, payload)

    def claim(self, task_id, lease):
        task = self._tasks[task_id]
        if task.state != "pending":
            return False
        task.state = "leased"
        task.owner_id = lease.worker_id
        task.owner_generation = lease.generation
        return True

    def complete(self, task_id, lease):
        task = self._tasks[task_id]
        if task.state != "leased" or task.owner_id != lease.worker_id:
            return False
        task.state = "done"
        task.owner_id = None
        task.owner_generation = None
        return True

    def requeue_owned(self, lease):
        count = 0
        for task in self._tasks.values():
            if task.state == "leased" and task.owner_id == lease.worker_id:
                task.state = "pending"
                task.owner_id = None
                task.owner_generation = None
                count += 1
        return count

    def get(self, task_id):
        return self._tasks[task_id]

